import pytest
from your_module import flatten_dict  # Replace with actual module name


# ── Happy path ────────────────────────────────────────────────────────────────

class TestFlattenDictHappyPath:
    def test_simple_flat_dict_is_unchanged(self):
        """A dict with no nested dicts should come back identical."""
        d = {"a": 1, "b": 2, "c": 3}
        assert flatten_dict(d) == {"a": 1, "b": 2, "c": 3}

    def test_single_level_nesting(self):
        d = {"a": {"b": 1}}
        assert flatten_dict(d) == {"a.b": 1}

    def test_multiple_keys_single_level_nesting(self):
        d = {"a": {"b": 1, "c": 2}, "d": 3}
        assert flatten_dict(d) == {"a.b": 1, "a.c": 2, "d": 3}

    def test_two_levels_of_nesting(self):
        d = {"a": {"b": {"c": 1}}}
        assert flatten_dict(d) == {"a.b.c": 1}

    def test_deeply_nested(self):
        d = {"l1": {"l2": {"l3": {"l4": {"l5": "deep"}}}}}
        assert flatten_dict(d) == {"l1.l2.l3.l4.l5": "deep"}

    def test_mixed_value_types(self):
        d = {
            "int": 1,
            "float": 3.14,
            "str": "hello",
            "list": [1, 2, 3],
            "none": None,
            "bool": True,
        }
        result = flatten_dict(d)
        assert result["int"] == 1
        assert result["float"] == 3.14
        assert result["str"] == "hello"
        assert result["list"] == [1, 2, 3]
        assert result["none"] is None
        assert result["bool"] is True

    def test_custom_separator(self):
        d = {"a": {"b": {"c": 42}}}
        assert flatten_dict(d, sep="/") == {"a/b/c": 42}

    def test_custom_separator_underscore(self):
        d = {"a": {"b": 1}}
        assert flatten_dict(d, sep="_") == {"a_b": 1}

    def test_parent_key_prefix(self):
        d = {"b": {"c": 1}}
        assert flatten_dict(d, parent_key="a") == {"a.b.c": 1}

    def test_list_values_are_preserved_not_flattened(self):
        """Lists should be treated as leaf values, not recursed into."""
        d = {"a": [1, 2, 3], "b": {"c": [4, 5]}}
        assert flatten_dict(d) == {"a": [1, 2, 3], "b.c": [4, 5]}

    def test_sibling_nested_dicts(self):
        d = {"x": {"a": 1}, "y": {"b": 2}}
        assert flatten_dict(d) == {"x.a": 1, "y.b": 2}


